import{_ as n,C as i,o as t,c,a3 as o,b as p,w as a,a as s,E as d,a4 as l}from"./chunks/framework.C49Ar5GK.js";const f=JSON.parse('{"title":"从推理到训练：跟完一次 step","description":"逐阶段跟踪 prompt 如何经 AgentLoop、TransferQueue、ReplayBuffer、reward、log-prob、advantage 和 actor update 闭环","frontmatter":{"title":"从推理到训练：跟完一次 step","description":"逐阶段跟踪 prompt 如何经 AgentLoop、TransferQueue、ReplayBuffer、reward、log-prob、advantage 和 actor update 闭环","lesson":{"stage":"04 · 源码","order":16,"time":"60–90 分钟","level":"核心必读","question":"一条 prompt 在 V1 中何时生成、何时取样、何时补字段，又何时让新权重回到 rollout？"}},"headers":[],"relativePath":"internals/rollout-to-update.md","filePath":"internals/rollout-to-update.md","lastUpdated":null}'),u={name:"internals/rollout-to-update.md"};function _(A,e,E,h,g,m){const r=i("Mermaid");return t(),c("div",null,[e[2]||(e[2]=o('<h1 id="从推理到训练-跟完一次-step" tabindex="-1">从推理到训练：跟完一次 <code>step()</code> <a class="header-anchor" href="#从推理到训练-跟完一次-step" aria-label="Permalink to &quot;从推理到训练：跟完一次 `step()`&quot;">​</a></h1><p>当前 V1 最值得逐行读的是 <code>PPOTrainer.step()</code> 与 <code>_step_once()</code>。前者提交生成并按参数同步频率组织本地更新，后者补齐训练字段并更新模型。</p><h2 id="先用人话-两条流水线在这里咬合" tabindex="-1">先用人话：两条流水线在这里咬合 <a class="header-anchor" href="#先用人话-两条流水线在这里咬合" aria-label="Permalink to &quot;先用人话：两条流水线在这里咬合&quot;">​</a></h2><p>生成流水线不断把 prompt 变成轨迹并写入仓库；训练流水线从仓库挑完整组，依次补 reward、概率、value、advantage，再更新参数。同步模式下一步结束后把新权重送回生成端。关键不是函数数量，而是<strong>每一步需要哪些字段已经存在</strong>。</p><h2 id="完整时序" tabindex="-1">完整时序 <a class="header-anchor" href="#完整时序" aria-label="Permalink to &quot;完整时序&quot;">​</a></h2>',5)),(t(),p(l,null,{default:a(()=>[d(r,{id:"mermaid-15",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20D%20as%20DataLoader%0A%20%20%20%20participant%20T%20as%20PPOTrainer%0A%20%20%20%20participant%20A%20as%20AgentLoop%0A%20%20%20%20participant%20L%20as%20LLM%20Server%0A%20%20%20%20participant%20Q%20as%20TransferQueue%0A%20%20%20%20participant%20B%20as%20ReplayBuffer%0A%20%20%20%20participant%20W%20as%20Train%20WorkerGroups%0A%20%20%20%20participant%20C%20as%20CheckpointEngine%0A%0A%20%20%20%20T-%3E%3ED%3A%20_next_train_batch()%0A%20%20%20%20D--%3E%3ET%3A%20TensorDict%20prompts%0A%20%20%20%20T-%3E%3EQ%3A%20prompt%20tag%20%3D%20pending%0A%20%20%20%20T-%3E%3EA%3A%20generate_sequences%EF%BC%88%E4%B8%8D%E7%AD%89%E7%BB%93%E6%9E%9C%EF%BC%89%0A%20%20%20%20A-%3E%3EQ%3A%20prompt%20tag%20%3D%20running%0A%20%20%20%20A-%3E%3EL%3A%20n%20%E4%B8%AA%20session%20rollout%0A%20%20%20%20L--%3E%3EA%3A%20token%20%2F%20log-prob%20%2F%20output%0A%20%20%20%20A-%3E%3EQ%3A%20trajectory%20fields%20%2B%20tags%0A%20%20%20%20A-%3E%3EQ%3A%20prompt%20tag%20%3D%20finished%2Ffailure%0A%20%20%20%20T-%3E%3EB%3A%20sample(batch_size)%0A%20%20%20%20B-%3E%3EQ%3A%20%E8%BD%AE%E8%AF%A2%20tag%EF%BC%8C%E9%80%89%E5%AE%8C%E6%95%B4%20prompt%20group%0A%20%20%20%20B--%3E%3ET%3A%20KVBatchMeta(keys%2C%20tags)%0A%20%20%20%20T-%3E%3EW%3A%20reward%EF%BC%88%E8%8B%A5%E6%9C%AA%E5%9C%A8%20AgentLoop%20%E5%B9%B6%E5%8F%91%E5%AE%8C%E6%88%90%EF%BC%89%0A%20%20%20%20T-%3E%3EW%3A%20old%20log-prob%20%2F%20ref%20%2F%20values%0A%20%20%20%20T-%3E%3EQ%3A%20%E5%86%99%20advantage%20%2F%20returns%0A%20%20%20%20T-%3E%3EW%3A%20update%20critic%EF%BC%88%E5%8F%AF%E9%80%89%EF%BC%89%0A%20%20%20%20T-%3E%3EW%3A%20update%20actor%0A%20%20%20%20T-%3E%3EC%3A%20on_step_end%20%E2%86%92%20update_weights%0A%20%20%20%20C-%3E%3EL%3A%20%E6%96%B0%20actor%20%E6%9D%83%E9%87%8D%0A%20%20%20%20T-%3E%3EQ%3A%20kv_clear(%E5%B7%B2%E6%B6%88%E8%B4%B9%20keys)%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=o('<h2 id="_1-提交生成-不等待完整回答" tabindex="-1">1. 提交生成，不等待完整回答 <a class="header-anchor" href="#_1-提交生成-不等待完整回答" aria-label="Permalink to &quot;1. 提交生成，不等待完整回答&quot;">​</a></h2><p><code>_add_batch_to_generate()</code> 从 dataloader 取一批，为每条原始 prompt 生成 UUID，转换为 TensorDict，附加 <code>global_steps</code>。<code>_submit_batch_to_rollout()</code> 先在 TQ 注册 tag-only prompt marker：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key = &lt;uid&gt;</span></span>\n<span class="line"><span>tag = {is_prompt: true, status: pending, global_steps: N}</span></span></code></pre></div><p>然后 <code>AgentLoopManagerTQ.generate_sequences()</code> 把批次切给多个 worker。worker 内部用 asyncio 创建后台任务，因此 controller 提交完成不等于 rollout 已完成。</p><h2 id="_2-agentloop-写入轨迹" tabindex="-1">2. AgentLoop 写入轨迹 <a class="header-anchor" href="#_2-agentloop-写入轨迹" aria-label="Permalink to &quot;2. AgentLoop 写入轨迹&quot;">​</a></h2><p>每个 prompt 按 <code>rollout.n</code> 建立 session。单轮场景通常每个 session 只有一个 output；多轮 agent 可以有多个 output。轨迹 key 为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{uid}_{session_id}_{index}</span></span></code></pre></div><p>value 包含 prompt/response IDs、mask、input/position IDs、数据集元信息、多模态输入（原始图像/视频不会直接存入）及 reward 扩展字段；tag 包含长度、状态以及生成开始/结束的权重版本。</p><p>若 reward loop workers 已提供，AgentLoop postprocess 可以在写 TQ 前并发计算分数；若没有，trainer 在 <code>_compute_reward_colocate()</code> 中取必要字段、临时构造 reward 输入，再写回 <code>rm_scores</code>。</p><h2 id="_3-replaybuffer-等完整组" tabindex="-1">3. ReplayBuffer 等完整组 <a class="header-anchor" href="#_3-replaybuffer-等完整组" aria-label="Permalink to &quot;3. ReplayBuffer 等完整组&quot;">​</a></h2><p>ReplayBuffer 轮询 TQ metadata，只有 prompt marker 到达 <code>finished</code> 或 <code>failure</code> 才能采样。内置策略优先选择 <code>global_steps</code> 更小的 prompt，以减少陈旧轨迹堆积。</p><p>返回的不是完整大张量，而是 <code>KVBatchMeta(partition_id, keys, tags)</code>。若 staleness 超过阈值：</p><ul><li><code>drop</code>：删除过旧 trajectory，并记录 dropped/staleness 指标；</li><li><code>wait</code>：达到阈值的在途 prompt 未完成时暂停采样，以保持 dropless。</li></ul><p><code>failure</code> 组当前仍可能被选中，源码留有是否整组过滤的 TODO；自定义 agent 应明确失败输出和 reward 的约定。</p><h2 id="_4-step-once-按顺序补字段" tabindex="-1">4. <code>_step_once()</code> 按顺序补字段 <a class="header-anchor" href="#_4-step-once-按顺序补字段" aria-label="Permalink to &quot;4. `_step_once()` 按顺序补字段&quot;">​</a></h2>',15)),(t(),p(l,null,{default:a(()=>[d(r,{id:"mermaid-66",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20K%5BKVBatchMeta%5D%20--%3E%20R%5Breward%20score%5D%0A%20%20%20%20R%20--%3E%20BAL%5B%E6%8C%89%20seq%20length%20%E5%B9%B3%E8%A1%A1%2F%E8%A1%A5%E9%BD%90%5D%0A%20%20%20%20BAL%20--%3E%20O%5Bold_log_probs%20%2B%20entropy%5D%0A%20%20%20%20O%20--%3E%20REF%5Bref_log_prob%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20REF%20--%3E%20V%5Bvalues%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20V%20--%3E%20A%5Breward%20penalty%20%2F%20correction%20%2F%20advantage%5D%0A%20%20%20%20A%20--%3E%20C%5Bcritic%20update%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20C%20--%3E%20P%5Bactor%20update%5D%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<p>顺序有依赖：</p><ol><li><code>_balance_batch</code> 根据 actor DP size 与 mini-batch 约束做 padding、按序列 workload 重排；</li><li><code>_compute_old_log_prob</code> 通常由训练 actor 重算；rollout correction 的 bypass mode 会直接复用 <code>rollout_log_probs</code>；</li><li>reference 仅在 KL 配方需要时存在；critic 仅在 GAE 等配置需要时存在；</li><li><code>_compute_advantage</code> 把 TQ 的 jagged 字段补齐为 DataProto，应用 reward KL / correction / estimator，再把结果还原成 nested tensor 写回；</li><li>critic 与 actor worker 按各自 PPO epochs/mini-batch 配置读取所需字段并训练。</li></ol><h2 id="_5-更新后的权重何时进入-rollout" tabindex="-1">5. 更新后的权重何时进入 rollout <a class="header-anchor" href="#_5-更新后的权重何时进入-rollout" aria-label="Permalink to &quot;5. 更新后的权重何时进入 rollout&quot;">​</a></h2><p>同步 trainer 的 <code>on_step_end()</code> 调用 <code>checkpoint_manager.update_weights(global_steps)</code>，唤醒 replicas 并同步新版本；<code>on_sample_end()</code> 会让 replicas 休眠并释放/丢弃相应权重与 KV cache。这解释了共置场景中显存为什么在 rollout 与训练阶段变化。</p><p><code>separate_async</code> 不会照搬这个每步时序，它用 <code>parameter_sync_step</code> 控制同步频率。比较同步/异步实验时必须记录每条轨迹的生成版本跨度，而不只记录吞吐。</p><h2 id="_6-step-结束并不只有训练" tabindex="-1">6. step 结束并不只有训练 <a class="header-anchor" href="#_6-step-结束并不只有训练" aria-label="Permalink to &quot;6. step 结束并不只有训练&quot;">​</a></h2><p><code>fit()</code> 还会在配置的频率上保存 checkpoint、验证、聚合 timing/训练指标、可选 dump rollout，最后 <code>tq.kv_clear</code> 清理已消费 keys。若进程在 clear 之前失败，重启语义取决于 TQ backend 和 checkpoint/replay 状态，不能假设像纯 dataloader 一样无状态重放。</p><h2 id="本课实作-追一个-uid" tabindex="-1">本课实作：追一个 uid <a class="header-anchor" href="#本课实作-追一个-uid" aria-label="Permalink to &quot;本课实作：追一个 uid&quot;">​</a></h2><p>选一个 prompt uid，记录五个时刻：注册 pending marker、session key 写入、ReplayBuffer 选中、advantage 写回、消费后 clear。每个时刻写“只拿 key/tag 还是读取 value”。最后把 <code>_step_once()</code> 九个阶段的输入字段列出来；这是以后插入自定义算法最重要的契约表。</p><p>下一步：<a href="./data-structures">数据结构与组织</a>。</p>',10))])}const B=n(u,[["render",_]]);export{f as __pageData,B as default};
